import '../styles/Menu.css'
import absence from '../assets/absence.png'
import employes from '../assets/employes.png'
import presence from '../assets/presence.png'
import graphique from '../assets/graphique.png'
import { Link } from 'react-router'
import supabase from './supabaseClient'
import React, {useState, useEffect} from 'react'

function Employés(){
    const [pointages, setPointages] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        async function fetchPointages() {
        const { data, error } = await supabase
            .from('USERINFO')
            .select(`USERID, Badgenumber, Name, Gender, TITLE`);

        console.log('📄 Résultat data :', data);
        console.log('⚠️ Erreur :', error);

        if (error) {
            console.error('Erreur de récupération :', error.message);
        } else {
            setPointages(data);
        }
        setLoading(false);
        }

        fetchPointages();
    }, []);

    if (loading) return <p>Chargement des données...</p>;

    return(
        <div >
            <table border="1" cellPadding="8" cellSpacing="0">
                <thead>
               
                </thead>     <tr>
                        <th>User ID</th>
                        <th>Numero de Badge</th>
                        <th>Name</th>
                        <th>Genre</th>
                        <th>Titre</th>
                    </tr>
                <tbody>
                    {pointages.map((p, index) => (
                        <tr key={index}>
                            <td>{p.USERID}</td>
                            <td>{p.Badgenumber}</td>
                            <td>{p.Name}</td>
                            <td>{p.Gender}</td>
                            <td>{p.TITLE}</td>
                        </tr>
                    ))}
                </tbody>
        </table>
        </div>
    )
}

export default Employés
